import heapq
from typing import List

class FoodRatings:

    def __init__(self, foods: List[str], cuisines: List[str], ratings: List[int]):
        self.food_to_rating = {}
        self.cuisine_to_heap = {}
        for food, cuisine, rating in zip(foods, cuisines, ratings):
            self.food_to_rating[food] = rating
            if cuisine not in self.cuisine_to_heap:
                self.cuisine_to_heap[cuisine] = []
            heapq.heappush(self.cuisine_to_heap[cuisine], (-rating, food))

    def changeRating(self, food: str, newRating: int) -> None:
        old_rating = self.food_to_rating[food]
        self.food_to_rating[food] = newRating
        for cuisine, heap in self.cuisine_to_heap.items():
            for i, (rating, f) in enumerate(heap):
                if f == food:
                    heap[i] = (-newRating, food)
                    heapq.heapify(heap)
                    break

    def highestRated(self, cuisine: str) -> str:
        while self.cuisine_to_heap[cuisine][0][0] != -self.food_to_rating[self.cuisine_to_heap[cuisine][0][1]]:
            heapq.heappop(self.cuisine_to_heap[cuisine])
        return self.cuisine_to_heap[cuisine][0][1]
```

